// Upload image to Cloudinary with transformations
const result = await cloudinary.uploader.upload("image.jpg", {
  folder: "products",
  transformation: [
    { width: 800, height: 600, crop: "fill" },
    { quality: "auto", fetch_format: "auto" },
  ],
  tags: ["product", "featured"],
});

